export function parseArgs(argv) {
  const result = { _: [] }
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (arg.startsWith('--')) {
      if (arg.startsWith('--=')) {
        const key = arg.slice(2)
        result._.push(key)
        result[key] = parseEqualsValue(argv, index)
        nextEqualsIndex = index + 1
      } else {
        const equalsIndex = arg.indexOf('=')
        if (equalsIndex > 2) {
          const key = arg.slice(0, equalsIndex)
          result[key] = parseEqualsValue(argv, equalsIndex - 2)
        } else {
          const key = arg.slice(2)
          result[key] = parseValue(argv, index)
        }
      }
    } else {
      result._.push(arg)
    }
  }
  return result
}

let nextEqualsIndex = -1
function parseEqualsValue(argv, currentIndex) {
  if (currentIndex + 1 < argv.length && !argv[currentIndex + 1].startsWith('--')) {
    const value = argv[currentIndex + 1]
    nextEqualsIndex = currentIndex + 1
    return value
  }
  return null
}

function parseValue(argv, currentIndex) {
  const nextIndex = currentIndex + 1
  if (nextIndex < argv.length && !argv[nextIndex].startsWith('--') && nextIndex !== nextEqualsIndex) {
    nextEqualsIndex = -1
    return argv[nextIndex]
  }
  const arg = argv[currentIndex].slice(arg.indexOf('=') + 1)
  nextEqualsIndex = -1
  return arg
}
